 {"id":"bd-3tpn","title":"E2E test for API failure user experience","description":"## Purpose
End-to-end tests verifying user experience when API is unavailable in production, ensuring errors are visible and actionable.

## Test File Location
`apps/web/e2e/api-failure-ux.e2e.test.ts`

## Test Scenarios

### Scenario 1: Dashboard Load With API Down
```typescript
describe("E2E: API Failure UX - Dashboard", () => {
  test("should show clear error state when API is unavailable", async ({ page }) => {
    // Block all API requests
    await page.route("**/api/**", route => {
      console.log(`[E2E] Blocking API request: ${route.request().url()}`);
      route.fulfill({ status: 503, body: JSON.stringify({ error: "Service unavailable" }) });
    });

    console.log("[E2E] Navigating to dashboard...");
    await page.goto("/dashboard");

    // Wait for error state to render
    await expect(page.locator("[data-testid=error-banner]")).toBeVisible({ timeout: 10000 });
    console.log("[E2E] Error banner is visible");

    // Verify error message is user-friendly
    const errorText = await page.locator("[data-testid=error-banner]").textContent();
    console.log(`[E2E] Error banner text: "${errorText}"`);

    expect(errorText).not.toContain("500");  // No raw status codes
    expect(errorText).not.toContain("undefined");  // No undefined
    expect(errorText).toMatch(/unable to load|connection|unavailable/i);

    // Screenshot for visual verification
    await page.screenshot({ path: "e2e-screenshots/api-failure-dashboard.png" });
    console.log("[E2E] Screenshot saved: api-failure-dashboard.png");
  });

  test("should NOT show mock data in production build", async ({ page }) => {
    await page.route("**/api/snapshot", route => {
      route.fulfill({ status: 500 });
    });

    await page.goto("/dashboard");
    await page.waitForLoadState("networkidle");

    // Should NOT see mock agent data
    const agentCards = page.locator("[data-testid=agent-card]");
    const count = await agentCards.count();
    console.log(`[E2E] Agent cards visible: ${count}`);

    // In production with API down, should be 0 agents (not mock data)
    expect(count).toBe(0);

    // Should see empty state or error, not fake data
    await expect(page.locator("[data-testid=empty-state], [data-testid=error-state]")).toBeVisible();
    console.log("[E2E] PASS: No mock data shown in production");
  });

  test("should display toast notification on API failure", async ({ page }) => {
    await page.route("**/api/**", route => route.fulfill({ status: 503 }));

    await page.goto("/dashboard");

    // Wait for toast to appear
    const toast = page.locator("[data-testid=toast], .toast, [role=alert]");
    await expect(toast).toBeVisible({ timeout: 5000 });

    const toastText = await toast.textContent();
    console.log(`[E2E] Toast text: "${toastText}"`);

    expect(toastText).toMatch(/failed|error|unavailable/i);
    await page.screenshot({ path: "e2e-screenshots/api-failure-toast.png" });
  });
});
```

### Scenario 2: Retry Mechanism
```typescript
describe("E2E: API Failure UX - Retry", () => {
  test("should provide working retry button", async ({ page }) => {
    let apiCallCount = 0;

    await page.route("**/api/snapshot", route => {
      apiCallCount++;
      console.log(`[E2E] API call #${apiCallCount}`);

      if (apiCallCount === 1) {
        route.fulfill({ status: 503 });
      } else {
        route.fulfill({ 
          status: 200, 
          body: JSON.stringify({ agents: [], timestamp: Date.now() }) 
        });
      }
    });

    await page.goto("/dashboard");

    // Wait for error state
    await expect(page.locator("[data-testid=error-state]")).toBeVisible();
    console.log("[E2E] Error state shown after first failed request");

    // Find and click retry button
    const retryButton = page.locator("button:has-text(\"Retry\"), button:has-text(\"Try Again\")");
    await expect(retryButton).toBeVisible();
    console.log("[E2E] Retry button is visible");

    await retryButton.click();
    console.log("[E2E] Clicked retry button");

    // Wait for success state
    await expect(page.locator("[data-testid=error-state]")).not.toBeVisible({ timeout: 5000 });
    console.log("[E2E] Error state cleared after retry");

    expect(apiCallCount).toBe(2);
    await page.screenshot({ path: "e2e-screenshots/api-retry-success.png" });
    console.log("[E2E] PASS: Retry mechanism works");
  });

  test("should show retry button after multiple failures", async ({ page }) => {
    await page.route("**/api/**", route => route.fulfill({ status: 500 }));

    await page.goto("/dashboard");

    // Click retry multiple times
    for (let i = 0; i < 3; i++) {
      await expect(page.locator("[data-testid=error-state]")).toBeVisible();
      const retryButton = page.locator("button:has-text(\"Retry\")");
      if (await retryButton.isVisible()) {
        await retryButton.click();
        console.log(`[E2E] Retry attempt ${i + 1}`);
        await page.waitForTimeout(500);
      }
    }

    // Retry button should still be available
    await expect(page.locator("button:has-text(\"Retry\")")).toBeVisible();
    console.log("[E2E] PASS: Retry button persists after multiple failures");
  });
});
```

