### Scenario 4: Network Timeout
```typescript
describe("E2E: API Failure UX - Network Issues", () => {
  test("should handle network timeout gracefully", async ({ page }) => {
    await page.route("**/api/snapshot", async route => {
      console.log("[E2E] Simulating slow network (10s delay)...");
      await new Promise(r => setTimeout(r, 10000));  // Exceed timeout
      route.fulfill({ status: 200, body: "{}" });
    });

    await page.goto("/dashboard");

    // Should show loading state initially
    await expect(page.locator("[data-testid=loading-skeleton]")).toBeVisible();
    console.log("[E2E] Loading skeleton visible");

    // After timeout, should show error (not hang forever)
    await expect(page.locator("[data-testid=error-state]")).toBeVisible({ timeout: 15000 });
    console.log("[E2E] PASS: Timeout handled gracefully");
  });

  test("should handle intermittent connectivity", async ({ page }) => {
    let requestCount = 0;
    await page.route("**/api/snapshot", route => {
      requestCount++;
      // Every other request fails
      if (requestCount % 2 === 1) {
        route.abort("connectionfailed");
      } else {
        route.fulfill({ status: 200, body: JSON.stringify({ agents: [] }) });
      }
    });

    await page.goto("/dashboard");

    // Should eventually show data (after auto-retry or manual retry)
    const retryButton = page.locator("button:has-text(\"Retry\")");
    if (await retryButton.isVisible()) {
      await retryButton.click();
    }

    await expect(page.locator("[data-testid=dashboard-content]")).toBeVisible({ timeout: 10000 });
    console.log("[E2E] PASS: Recovered from intermittent connectivity");
  });
});
```

